// Get the LLM response (now plain text, not JSON)
const response = $input.first().json.text || $input.first().json.response;

// Get contact data
const findConvNode = $('Find Conversation').first().json;
const contactId = findConvNode.conversations[0].contactId;

const callDate = new Date().toLocaleDateString('en-US', { 
  month: 'short', 
  day: 'numeric', 
  year: 'numeric' 
});

return {
  json: {
    contact_id: contactId,
    formatted_note: `📞 Call Summary (${callDate})\n\n${response}`
  }
};

// Employee lookup map - add your team's GHL user IDs and names
const EMPLOYEE_NAMES = {
  'YOUR_EMPLOYEE_2_USER_ID': '{{YOUR_SALES_REP}}',
  'YOUR_EMPLOYEE_1_USER_ID': 'Employee 2',
  'YOUR_EMPLOYEE_3_USER_ID': 'Employee 2',
  'YOUR_EMPLOYEE_4_USER_ID': 'Employee 3'
  // Add more employees here as they join
};

// Get names from available data
const webhookData = $('Webhook Trigger').first().json.body;
const extractMessageData = $('Extract MessageID').first().json;

// Get employee name from userId (from Extract MessageID node)
const userId = extractMessageData.userId;
const employeeName = EMPLOYEE_NAMES[userId] || 'Team Rep';

// Get customer first name from webhook
const customerName = webhookData.customData?.first_name || 'Customer';

// Get all transcript items as an array
const transcript = $input.all().map(item => item.json);

// Combine consecutive messages from same speaker and clean markers
let consolidated = [];
let currentSpeaker = null;
let currentText = [];

transcript.forEach(item => {
  // mediaChannel 1 = Customer, mediaChannel 2 = Team Rep
  const speaker = item.mediaChannel === 1 ? customerName : employeeName;

  const cleanText = item.transcript
    .replace(/\[laugh\]/g, '')
    .replace(/\[hes\]/g, '')
    .replace(/\[noise\]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  if (!cleanText) return;

  if (speaker === currentSpeaker) {
    currentText.push(cleanText);
  } else {
    if (currentSpeaker !== null) {
      consolidated.push(`${currentSpeaker}: ${currentText.join(' ')}`);
    }
    currentSpeaker = speaker;
    currentText = [cleanText];
  }
});

// Add final speaker's text
if (currentSpeaker !== null) {
  consolidated.push(`${currentSpeaker}: ${currentText.join(' ')}`);
}

const fullTranscript = consolidated.join('\n\n');

return {
  json: {
    fullTranscript: fullTranscript,
    employeeName: employeeName,  
    customerName: customerName 
  }
};

const messages = $input.item.json.messages.messages;

if (!messages || messages.length === 0) {
  throw new Error('No messages found in conversation');
}

// Find call message (should be most recent)
const callTypes = ['TYPE_CALL', 'TYPE_IVR_CALL', 'TYPE_CUSTOM_CALL'];
const callMessage = messages.find(m => callTypes.includes(m.messageType));

if (!callMessage) {
  throw new Error('No call message found - webhook may have fired incorrectly');
}

return {
  json: {
    messageId: callMessage.id,
    locationId: callMessage.locationId,
    userId: callMessage.userId || null  
  }
};
